fn caesar_encode(text: &str, shift: u8) -> String {
    text.chars().map(|c| {
        if c.is_ascii_lowercase() {
            (b'a' + (c as u8 - b'a' + shift) % 26) as char
        } else if c.is_ascii_uppercase() {
            (b'A' + (c as u8 - b'A' + shift) % 26) as char
        } else {
            c
        }
    }).collect()
}

fn main() {
    println!("{}", caesar_encode("Hello, World!", 3));
}

