fn fibonacci(n: u32) -> Vec<u64> {
    if n == 0 {
        return vec![];
    }
    let mut fibs = Vec::with_capacity(n as usize);
    for i in 0..n as usize {
        if i == 0 {
            fibs.push(0);
        } else if i == 1 {
            fibs.push(1);
        } else {
            fibs.push(fibs[i - 1] + fibs[i - 2]);
        }
    }
    fibs
}

