solution.code:
fn spiral_order(matrix: &[Vec<i32>]) -> Vec<i32> {
    let mut result = vec![];
    if matrix.is_empty() {
        return result;
    }
    let mut top = 0i32;
    let mut bottom = matrix.len() as i32 - 1;
    let mut left = 0i32;
    let mut right = matrix[0].len() as i32 - 1;
    while top <= bottom && left <= right {
        for j in left..=right {
            result.push(matrix[top as usize][j as usize]);
        }
        top += 1;
        for i in top..=bottom {
            result.push(matrix[i as usize][right as usize]);
        }
        right -= 1;
        if top <= bottom {
            for j in (left..=right).rev() {
                result.push(matrix[bottom as usize][j as usize]);
            }
            bottom -= 1;
        }
        if left <= right {
            for i in (top..=bottom).rev() {
                result.push(matrix[i as usize][left as usize]);
            }
            left += 1;
        }
    }
    result
}

fn main() {
    let m = vec![vec![1,2,3], vec![4,5,6], vec![7,8,9]];
    println!("{:?}", spiral_order(&m));
}

