solution.code:
fn is_valid_brackets(s: &str) -> bool {
    let mut stack: Vec<char> = Vec::new();
    for c in s.chars() {
        match c {
            '(' | '[' | '{' => stack.push(c),
            ')' => if stack.pop() != Some('(') { return false; },
            ']' => if stack.pop() != Some('[') { return false; },
            '}' => if stack.pop() != Some('{') { return false; },
            _ => {},
        }
    }
    stack.is_empty()
}

fn main() {
    println!("{}", is_valid_brackets("({[]})")); 
    println!("{}", is_valid_brackets("([)]")); 
    println!("{}", is_valid_brackets("")); 
}

