    let mut cache = LruCache::new(2);
    cache.put(1, 10);
    cache.put(2, 20);
    println!("{:?}", cache.get(1));
    cache.put(3, 30);
    println!("{:?}", cache.get(2));
    println!("{:?}", cache.get(3));
}

