solution.code:
fn knapsack(weights: &[usize], values: &[usize], capacity: usize) -> usize {
    let n = weights.len();
    let mut dp = vec![0usize; capacity + 1];
    for i in 0..n {
        for w in (weights[i]..=capacity).rev() {
            dp[w] = dp[w].max(dp[w - weights[i]] + values[i]);
        }
    }
    dp[capacity]
}

fn main() {
    println!("{}", knapsack(&[1, 2, 3], &[6, 10, 12], 5));
    println!("{}", knapsack(&[2, 3, 4, 5], &[3, 4, 5, 6], 5));
}

